type BankAccount {
    owner: Text;
    balance: Int;

    fn deposit(amount: Int) -> Void {
        self.balance = self.balance + amount;
        ret;
    }

    fn withdraw(amount: Int) -> Bool {
        if self.balance >= amount {
            self.balance = self.balance - amount;
            ret true;
        }
        ret false;
    }
}

fn main() -> Void {
    let account: BankAccount = new BankAccount();
    account.owner = "Alice";
    account.balance = 1000;

    let success: Bool = account.withdraw(200);

    fx {
        if success {
            println("Withdrawal successful. New balance: ", account.balance);
        } else {
            println("Insufficient funds.");
        }
    }

    account.deposit(500);
    fx {
        println("Final balance: ", account.balance);
    }
    ret;
}

fn main() -> Void {
    let buffer: Int[] = [10, 20, 30, 40, 50];
    let size: Int = length(buffer);
    let first: Int = buffer[0];
    buffer[2] = 99;

    if first < 0 {
        fx {
            println("unreachable");
        }
    }

    loop i in 0..size {
        let current: Int = buffer[i];
        if current % 2 == 0 {
            buffer[i] = current * 2;
        }
    }

    fx {
        println("Modified buffer:");
        loop i in 0..length(buffer) {
            println("  [", i, "]: ", buffer[i]);
        }
    }
    ret;
}

