use "severity_rules";
use "severity_labels";

type Finding {
    name: Text;
    score: Int;
}

fn main() -> Void {
    let alpha: Finding = Finding { name: "alpha", score: 95 };
    let beta: Finding = Finding { name: "beta", score: 80 };
    let gamma: Finding = Finding { name: "gamma", score: 40 };
    let items: Finding[] = [];
    items = items + [alpha];
    items = items + [beta];
    items = items + [gamma];

    let count: Int = length(items);
    loop i in 0..count {
        let item: Finding = items[i];
        let level: Text = classifySeverity(item.score);
        let prefix: Text = severityPrefix(level);
        fx {
            println(prefix, " ", item.name);
        }
    }

    fx {
        println("threshold = ", WarmThreshold);
    }
    ret;
}

